import{_ as l,o as e,c as t,a2 as i}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"巴菲特致股东信核心总结 · 1998年","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1998年/核心总结.md","filePath":"01_letters/1998年/核心总结.md"}'),r={name:"01_letters/1998年/核心总结.md"};function h(o,a,d,n,u,s){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="巴菲特致股东信核心总结-·-1998年" tabindex="-1">巴菲特致股东信核心总结 · 1998年 <a class="header-anchor" href="#巴菲特致股东信核心总结-·-1998年" aria-label="Permalink to &quot;巴菲特致股东信核心总结 · 1998年&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净值增长259亿美元，每股账面价值增长48.3%</li><li>过去34年每股账面价值从19美元增长至37,801美元，年复合增长率24.7%</li><li>48.3%增幅主要来自收购中发行股份，实际内在价值增长远低于账面价值增幅</li></ul><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="通用再保险公司-gen-re" tabindex="-1">通用再保险公司（Gen Re） <a class="header-anchor" href="#通用再保险公司-gen-re" aria-label="Permalink to &quot;通用再保险公司（Gen Re）&quot;">​</a></h3><ul><li>以220亿美元收购，美国最大的财产意外再保险公司</li><li>同时获得科隆再保险82%股权，业务覆盖124个国家</li><li>收购后浮存金大幅增加至227.62亿美元</li></ul><h3 id="公务机航空公司-eja-netjets" tabindex="-1">公务机航空公司（EJA/NetJets） <a class="header-anchor" href="#公务机航空公司-eja-netjets" aria-label="Permalink to &quot;公务机航空公司（EJA/NetJets）&quot;">​</a></h3><ul><li>以7.25亿美元收购，部分所有权行业的开创者和领导者</li><li>拥有超过1,000名客户和163架飞机</li><li>巴菲特家族亲自使用并高度评价该服务</li></ul><h2 id="保险业务核心观点" tabindex="-1">保险业务核心观点 <a class="header-anchor" href="#保险业务核心观点" aria-label="Permalink to &quot;保险业务核心观点&quot;">​</a></h2><h3 id="浮存金概念" tabindex="-1">浮存金概念 <a class="header-anchor" href="#浮存金概念" aria-label="Permalink to &quot;浮存金概念&quot;">​</a></h3><ul><li>浮存金是保险公司持有但不拥有的资金</li><li>关键决定因素：浮存金数量、成本、长期前景</li><li>伯克希尔32年平均浮存金成本远低于零，实现承保利润</li></ul><h3 id="保险业务数据" tabindex="-1">保险业务数据 <a class="header-anchor" href="#保险业务数据" aria-label="Permalink to &quot;保险业务数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>平均浮存金（百万美元）</th></tr></thead><tbody><tr><td>1967</td><td>17</td></tr><tr><td>1987</td><td>1,267</td></tr><tr><td>1997</td><td>7,093</td></tr><tr><td>1998</td><td>22,762</td></tr></tbody></table><h2 id="盖可保险-geico" tabindex="-1">盖可保险（GEICO） <a class="header-anchor" href="#盖可保险-geico" aria-label="Permalink to &quot;盖可保险（GEICO）&quot;">​</a></h2><ul><li>保单持有人从1993年的200万增长至1998年的356万</li><li>营销预算从1995年的3,300万美元增至1.43亿美元</li><li>投诉比率远低于主要竞争对手</li></ul><h2 id="投资组合" tabindex="-1">投资组合 <a class="header-anchor" href="#投资组合" aria-label="Permalink to &quot;投资组合&quot;">​</a></h2><p>主要持仓（市值超过7.5亿美元）：</p><ul><li>可口可乐：134亿美元</li><li>美国运通：51.8亿美元</li><li>吉列：45.9亿美元</li><li>富国银行：25.4亿美元</li></ul><h2 id="管理哲学" tabindex="-1">管理哲学 <a class="header-anchor" href="#管理哲学" aria-label="Permalink to &quot;管理哲学&quot;">​</a></h2><h3 id="对ceo的管理方式" tabindex="-1">对CEO的管理方式 <a class="header-anchor" href="#对ceo的管理方式" aria-label="Permalink to &quot;对CEO的管理方式&quot;">​</a></h3><ul><li>不干预优秀CEO的经营决策</li><li>给予完全的自主权和长期视角</li><li>消除仪式性和非生产性活动</li><li>要求像拥有100%所有权一样经营业务</li></ul><h3 id="薪酬政策" tabindex="-1">薪酬政策 <a class="header-anchor" href="#薪酬政策" aria-label="Permalink to &quot;薪酬政策&quot;">​</a></h3><ul><li>盖可保险奖金50%基于成熟保单收益，50%基于增长</li><li>排除第一年新业务的获取成本</li></ul><h2 id="会计批评" tabindex="-1">会计批评 <a class="header-anchor" href="#会计批评" aria-label="Permalink to &quot;会计批评&quot;">​</a></h2><h3 id="股票期权会计" tabindex="-1">股票期权会计 <a class="header-anchor" href="#股票期权会计" aria-label="Permalink to &quot;股票期权会计&quot;">​</a></h3><ul><li>现行会计原则忽略期权成本，是严重缺陷</li><li>提出三个问题：如果期权不是薪酬是什么？如果薪酬不是费用是什么？如果费用不应该计入收益应该放在哪里？</li></ul><h3 id="重组费用与并购会计" tabindex="-1">重组费用与并购会计 <a class="header-anchor" href="#重组费用与并购会计" aria-label="Permalink to &quot;重组费用与并购会计&quot;">​</a></h3><ul><li>批评利用重组费用操纵盈利的行为</li><li>1998年共识别1,369项特殊费用，总额721亿美元</li></ul><h2 id="其他要点" tabindex="-1">其他要点 <a class="header-anchor" href="#其他要点" aria-label="Permalink to &quot;其他要点&quot;">​</a></h2><ul><li>员工总数47,566人，总部仅12.8人</li><li>联邦所得税27亿美元，承担美国政府超过半天的开支</li><li>股东指定捐赠计划18年累计1.3亿美元</li></ul><hr><p><em>核心要点总结完成</em></p>',32)])])}const q=l(r,[["render",h]]);export{b as __pageData,q as default};
